const f = $json;
const langs = (f['Target Languages'] || 'en').split(',').map(l => l.trim());

const socialLinks = {};
if (f['Social Media Links']) {
  f['Social Media Links'].split(',').forEach(link => {
    const l = link.trim();
    if (l.includes('facebook')) socialLinks.facebook = l;
    else if (l.includes('twitter') || l.includes('x.com')) socialLinks.twitter = l;
    else if (l.includes('linkedin')) socialLinks.linkedin = l;
    else if (l.includes('instagram')) socialLinks.instagram = l;
  });
}

const slug = f['Website Name'].toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');

return {
  websiteName: f['Website Name'],
  purpose: f['Primary Purpose'],
  languages: langs,
  primaryLang: langs[0],
  designStyle: f['Design Style'],
  seoKeywords: f['SEO Keywords'],
  mainHeading: f['Main Heading'],
  description: f['Business Description'],
  contactEmail: f['Contact Email'],
  companyName: f['Company Name'] || f['Website Name'],
  phone: f['Phone Number'] || '',
  socialLinks: socialLinks,
  gaId: f['Google Analytics ID'] || '',
  fbPixelId: f['Facebook Pixel ID'] || '',
  specialFeatures: f['Special Features'] || '',
  slug: slug,
  timestamp: Date.now()
};

parameters.text:
=You are an expert SEO specialist. Analyze the following and generate SEO metadata as JSON.

Business: {{ $json.companyName }}
Purpose: {{ $json.purpose }}
Keywords: {{ $json.seoKeywords }}
Description: {{ $json.description }}
Languages: {{ $json.languages.join(', ') }}

Respond ONLY in valid JSON with these keys:
- metaTitle: SEO title (50-60 chars)
- metaDescription: meta description (150-160 chars)
- ogTitle: Open Graph title
- ogDescription: Open Graph description
- schemaType: Schema.org type (Organization, LocalBusiness, WebSite, etc.)
- schemaJson: complete Schema.org JSON-LD object as a string
- keywords: array of 10-15 SEO keywords
- h1Suggestion: suggested H1 tag text
- h2Suggestions: array of 3-5 H2 suggestions

=You are an expert web developer. Generate a complete, production-ready HTML page.

Requirements:
- Name: {{ $('Process Form Data').item.json.websiteName }}
- Purpose: {{ $('Process Form Data').item.json.purpose }}
- Languages: {{ $('Process Form Data').item.json.languages.join(', ') }} (primary: {{ $('Process Form Data').item.json.primaryLang }})
- Style: {{ $('Process Form Data').item.json.designStyle }}
- Heading: {{ $('Process Form Data').item.json.mainHeading }}
- Description: {{ $('Process Form Data').item.json.description }}
- Email: {{ $('Process Form Data').item.json.contactEmail }}
- Phone: {{ $('Process Form Data').item.json.phone }}
- Social: {{ JSON.stringify($('Process Form Data').item.json.socialLinks) }}
- Features: {{ $('Process Form Data').item.json.specialFeatures }}
- GA ID: {{ $('Process Form Data').item.json.gaId }}
- FB Pixel: {{ $('Process Form Data').item.json.fbPixelId }}

SEO Data:
{{ $json.text }}

Instructions:
1. Semantic HTML5, mobile-first responsive, modern design
2. Embed ALL SEO meta tags, Open Graph, Twitter Card, and Schema.org JSON-LD in head
3. Add language selector in nav with translations for each target language
4. Add hreflang link tags for all languages
5. Include <link rel="manifest" href="manifest.json"> in head
6. Register Service Worker before </body>
7. Embed Google Analytics and Facebook Pixel if IDs provided
8. Sections: hero, about/services, features, contact form, footer with social links
9. All CSS in <style>, all JS in <script>, NO external CDN links
10. Smooth animations, dark/light considerations, accessible (ARIA labels)

Return ONLY complete HTML from <!DOCTYPE html> to </html>.

