const pd = $('Process Form Data').item.json;
const style = pd.designStyle;
const themeColor = style.includes('Dark') ? '#111827' : style.includes('Tech') ? '#4F46E5' : style.includes('Creative') ? '#7C3AED' : '#3B82F6';
const bgColor = style.includes('Dark') ? '#000000' : '#ffffff';

const manifest = JSON.stringify({
  name: pd.websiteName,
  short_name: pd.companyName.substring(0, 12),
  description: pd.description.substring(0, 132),
  start_url: '/',
  display: 'standalone',
  background_color: bgColor,
  theme_color: themeColor,
  orientation: 'portrait-primary',
  icons: [
    { src: 'icon-192.png', sizes: '192x192', type: 'image/png' },
    { src: 'icon-512.png', sizes: '512x512', type: 'image/png' }
  ],
  lang: pd.primaryLang
}, null, 2);

const sw = `const CACHE='${pd.slug}-v1';
const URLS=['/','manifest.json'];
self.addEventListener('install',e=>e.waitUntil(caches.open(CACHE).then(c=>c.addAll(URLS))));
self.addEventListener('fetch',e=>e.respondWith(caches.match(e.request).then(r=>r||fetch(e.request))));
self.addEventListener('activate',e=>e.waitUntil(caches.keys().then(ks=>Promise.all(ks.filter(k=>k!==CACHE).map(k=>caches.delete(k))))));`;

const sitemap = `<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9" xmlns:xhtml="http://www.w3.org/1999/xhtml">\n${pd.languages.map(l=>`  <url>\n    <loc>https://YOUR_DOMAIN/${l==='en'?'':l+'/'}</loc>\n    <lastmod>${new Date().toISOString().split('T')[0]}</lastmod>\n    <priority>${l===pd.primaryLang?'1.0':'0.8'}</priority>\n  </url>`).join('\n')}\n</urlset>`;

const robots = `User-agent: *\nAllow: /\nSitemap: https://YOUR_DOMAIN/sitemap.xml`;

return { manifest, sw, sitemap, robots };

const htmlRaw = $('Generate Website HTML').item.json.text || '';
const pwa = $json;
const pd = $('Process Form Data').item.json;

let html = htmlRaw.trim();
if (html.startsWith('```html')) html = html.slice(7);
if (html.startsWith('```')) html = html.slice(3);
if (html.endsWith('```')) html = html.slice(0, -3);
html = html.trim();

const dIdx = html.toLowerCase().indexOf('<!doctype html>');
if (dIdx > 0) html = html.slice(dIdx);

if (!html.includes('manifest.json')) {
  html = html.replace('<head>', '<head>\n<link rel="manifest" href="manifest.json">');
}
if (!html.includes('serviceWorker')) {
  html = html.replace('</body>', '<script>if("serviceWorker" in navigator){navigator.serviceWorker.register("sw.js")}</script>\n</body>');
}

const fn = pd.slug + '-' + pd.timestamp;

return [
  { fileName: fn + '.html', content: html, contentType: 'text/html' },
  { fileName: 'manifest.json', content: pwa.manifest, contentType: 'application/json' },
  { fileName: 'sw.js', content: pwa.sw, contentType: 'application/javascript' },
  { fileName: 'sitemap.xml', content: pwa.sitemap, contentType: 'application/xml' },
  { fileName: 'robots.txt', content: pwa.robots, contentType: 'text/plain' }
];

const items = $input.all();
const pd = items[0].json;
const baseUrl = 'https://YOUR_S3_BUCKET_NAME.s3.YOUR_REGION.amazonaws.com';
const mainFile = items.find(i => i.json.fileName && i.json.fileName.endsWith('.html'));

return {
  status: 'success',
  websiteUrl: mainFile ? baseUrl + '/' + mainFile.json.fileName : baseUrl,
  filesUploaded: items.length,
  timestamp: new Date().toISOString()
};
